mapper.select:
select DISTINCT ON (a.equipment_id) a.write_year , a.doc_type , a.doc_no , a.comp_id , a.equipment_id , a.equipment_mgmt_num , a.equipment_mf_spec , a.inspection_cycle , a.inspection_expiry_date , a.use_yn , b.write_year as inspection_write_year , b.doc_seq , COALESCE(b.inspection_date, '') as inspection_date , COALESCE(b.next_inspection_date, '') as next_inspection_date , b.use_yn as i_use_yn , coalesce( nullif( (select string_agg(orgn_nm, ', ') from esg.tb_safety_mgmt_of_hazardous_machinery_orgn where write_year = a.write_year and doc_type = a.doc_type and doc_no = a.doc_no) , '') , '미설정') as card_orgn_nm , COALESCE(c.inspection_date, '') as last_inspection_date , COALESCE(c.next_inspection_date, '') as last_next_inspection_date , d.equipment_nm , e.orgn_id , e.orgn_nm , f.std_eq_nm , b.inspection_valid_from_dt , b.inspection_valid_to_dt , d.std_eq_id , d.std_eq_id as i_std_eq_id from esg.tb_safety_mgmt_of_hazardous_machinery a left join esg.tb_safety_mgmt_of_hazardous_machinery_inspections b on b.write_year = a.write_year and b.doc_type = a.doc_type and b.doc_no = a.doc_no left join (select z.write_year, z.doc_type, z.doc_no, z.inspection_date, z.next_inspection_date from esg.tb_safety_mgmt_of_hazardous_machinery_inspections z inner join (select write_year, doc_type, doc_no, max(doc_seq) doc_seq from esg.tb_safety_mgmt_of_hazardous_machinery_inspections where use_yn = 'Y' group by write_year, doc_type, doc_no) zz on zz.write_year = z.write_year and zz.doc_type = z.doc_type and zz.doc_no = z.doc_no and zz.doc_seq = z.doc_seq) c on c.write_year = a.write_year and c.doc_type = a.doc_type and c.doc_no = a.doc_no left join esg.tb_equipment_info d on d.equipment_id = a.equipment_id left join esg.tb_safety_mgmt_of_hazardous_machinery_orgn e on e.write_year = a.write_year and e.doc_type = a.doc_type and e.doc_no = a.doc_no left join esg.tb_dataset_typeofequipment f on a.comp_id = f.comp_id and d.std_eq_id = f.std_eq_id where a.comp_id = #{compId}
and ((NULLIF(b.inspection_date,'') IS NOT NULL AND TO_CHAR(NULLIF(b.inspection_date,'')::date,'YYYY') <= #{writeYear}) OR NULLIF(b.inspection_date,'') IS NULL )
order by a.equipment_id asc, a.use_yn desc, b.use_yn desc, b.inspection_date desc, b.doc_seq, e.orgn_id
-- select -- A.write_year, A.doc_type, A.doc_no, A.comp_id, A.equipment_id, A.equipment_mgmt_num, -- A.equipment_mf_spec, A.inspection_cycle, A.inspection_expiry_date, A.use_yn, -- B.write_year as o_write_year, B.doc_type as o_doc_type, B.doc_no as o_doc_no, B.orgn_id, B.orgn_nm, -- C.write_year as i_write_year, C.doc_type as i_doc_type, C.doc_no as i_doc_no, C.doc_seq, C.inspection_date, -- C.next_inspection_date, C.use_yn AS i_use_yn, -- D.equipment_nm -- from esg.tb_safety_mgmt_of_hazardous_machinery A -- left join esg.tb_safety_mgmt_of_hazardous_machinery_orgn B -- on A.doc_no = B.doc_no and A.write_year = B.write_year -- left join esg.tb_safety_mgmt_of_hazardous_machinery_inspections C -- on A.doc_no = C.doc_no and A.write_year = C.write_year -- left join esg.tb_equipment_info D -- on A.equipment_id = D.equipment_id -- order by A.use_yn desc, C.doc_seq asc;

select a.write_year , a.doc_type , a.doc_no , a.comp_id , a.equipment_id , a.equipment_mgmt_num , a.equipment_mf_spec , a.inspection_cycle , a.inspection_expiry_date , a.use_yn , b.write_year as inspection_write_year , b.doc_seq , COALESCE(b.inspection_date, '') as inspection_date , COALESCE(b.next_inspection_date, '') as next_inspection_date , b.use_yn as i_use_yn , coalesce( nullif( (select string_agg(orgn_nm, ', ') from esg.tb_safety_mgmt_of_hazardous_machinery_orgn where write_year = a.write_year and doc_type = a.doc_type and doc_no = a.doc_no) , '') , '미설정') as card_orgn_nm , COALESCE(c.inspection_date, '') as last_inspection_date , COALESCE(c.next_inspection_date, '') as last_next_inspection_date , d.equipment_nm , e.orgn_id , e.orgn_nm , f.std_eq_nm , b.inspection_valid_from_dt , b.inspection_valid_to_dt from esg.tb_safety_mgmt_of_hazardous_machinery a left join esg.tb_safety_mgmt_of_hazardous_machinery_inspections b on b.write_year = a.write_year and b.doc_type = a.doc_type and b.doc_no = a.doc_no left join (select z.write_year, z.doc_type, z.doc_no, z.inspection_date, z.next_inspection_date from esg.tb_safety_mgmt_of_hazardous_machinery_inspections z inner join (select write_year, doc_type, doc_no, max(doc_seq) doc_seq from esg.tb_safety_mgmt_of_hazardous_machinery_inspections where use_yn = 'Y' group by write_year, doc_type, doc_no) zz on zz.write_year = z.write_year and zz.doc_type = z.doc_type and zz.doc_no = z.doc_no and zz.doc_seq = z.doc_seq) c on c.write_year = a.write_year and c.doc_type = a.doc_type and c.doc_no = a.doc_no left join esg.tb_equipment_info d on d.equipment_id = a.equipment_id left join esg.tb_safety_mgmt_of_hazardous_machinery_orgn e on e.write_year = a.write_year and e.doc_type = a.doc_type and e.doc_no = a.doc_no left join esg.tb_dataset_typeofequipment f on a.comp_id = f.comp_id and d.std_eq_id = f.std_eq_id where a.comp_id = #{compId} and (b.use_yn is null or b.use_yn = 'Y') and a.doc_no IN
#{docNo}
order by a.equipment_id asc, a.use_yn desc, b.use_yn desc, b.inspection_date desc, b.doc_seq, e.orgn_id

mapper.update:
		UPDATE esg.tb_safety_mgmt_of_hazardous_machinery_inspections
		SET
            inspection_date = #{inspectionDate},
			inspection_valid_from_dt = #{inspectionValidFromDt},
			inspection_valid_to_dt = #{inspectionValidToDt},
            next_inspection_date = #{nextInspectionDate},
            use_yn = #{useYn},
            updated_at = now(),
            updated_by = #{updatedBy}

    	WHERE 
    		doc_seq = #{docSeq}
   		AND	doc_no = #{docNo}
   		AND	doc_type = #{docType}
   		AND write_year = #{writeYear};

mapper.select:
    	SELECT LPAD((COALESCE(MAX(CAST(A.doc_no AS INTEGER)), 0) + 1)::TEXT, 5, '0') AS docNo
	  		FROM esg.tb_safety_mgmt_of_hazardous_machinery A
	 	WHERE A.comp_id = #{compId}
	   	  AND A.write_year = #{writeYear}
	   	  AND A.doc_type = #{docType};

