		WHERE
			write_year = #{writeYear}
		AND	doc_type = #{docType}
		AND	doc_no = #{docNo}
		AND doc_seq = #{docSeq};

mapper.delete:
 	DELETE FROM esg.tb_safety_mgmt_of_hazardous_machinery_orgn A
 	WHERE 
 		A.write_year = #{writeYear}
